import{_ as e,o as i,c as a,aw as l}from"./chunks/framework.DLufY-ao.js";const r="/workbook/assets/list-linked.DVJCdc8w.png",k=JSON.parse('{"title":"Linked List (Связанный список)","description":"","frontmatter":{},"headers":[],"relativePath":"wiki/dev-commit/theory/data-structures/structures/linked-list.md","filePath":"wiki/dev-commit/theory/data-structures/structures/linked-list.md"}'),d={name:"wiki/dev-commit/theory/data-structures/structures/linked-list.md"};function s(o,t,n,c,h,u){return i(),a("div",null,[...t[0]||(t[0]=[l('<h1 id="linked-list-связанныи-список" tabindex="-1">Linked List (Связанный список) <a class="header-anchor" href="#linked-list-связанныи-список" aria-label="Permalink to &quot;Linked List (Связанный список)&quot;">​</a></h1><h2 id="информация" tabindex="-1">Информация <a class="header-anchor" href="#информация" aria-label="Permalink to &quot;Информация&quot;">​</a></h2><img src="'+r+'" width="350px"><div class="tip custom-block"><p class="custom-block-title">Связный список</p><ul><li><strong>Связный список</strong> - состоит из группы узлов, которые вместе образуют последовательность. Каждый узел содержит: <em>фактические данные</em>, которые в нем хранятся (это могут быть данные любого типа) и <em>указатель</em> (или ссылку) на следующий узел в последовательности</li><li>Cyществуют <strong>двусвязные списки</strong>: в них у каждого узла есть указатель и на следующий, и на предыдущий элемент в списке</li><li>Связанные списки хранят последовательность</li><li><em>Назначение</em>: Манипуляция данными</li><li>В JavaScript массивы динамические, но есть языки, где массивы статичные (размер должен быть фиксированным во время комиляции и не может изменяться динамически). Для языков со статичными массивами примеяюися связанные списки</li></ul></div><h2 id="плюсы-и-минусы" tabindex="-1">Плюсы и минусы <a class="header-anchor" href="#плюсы-и-минусы" aria-label="Permalink to &quot;Плюсы и минусы&quot;">​</a></h2><ul><li>[+] Быстрая вставка данных и их удаление</li><li>[+] Размер списка не должен быть фиксированным при компиляции, он может меняться динамически во время выполнения</li><li>[-] Занимает больше памяти, т.к. помимо данных хранится 1 или 2 указателя</li><li>[-] Долгий поиск элементов</li></ul><h2 id="операции" tabindex="-1">Операции <a class="header-anchor" href="#операции" aria-label="Permalink to &quot;Операции&quot;">​</a></h2><ul><li>Добавление элемента</li><li>Удаление элемента</li><li>Поиск элемента в списке</li></ul><h2 id="применение" tabindex="-1">Применение <a class="header-anchor" href="#применение" aria-label="Permalink to &quot;Применение&quot;">​</a></h2><ul><li>Последовательности</li><li>Для построения других структур данных (н-р: очередь)</li></ul><h2 id="сложность-алгоритма" tabindex="-1">Сложность алгоритма <a class="header-anchor" href="#сложность-алгоритма" aria-label="Permalink to &quot;Сложность алгоритма&quot;">​</a></h2><p><strong>Временная сложность связного списка</strong></p><table tabindex="0"><thead><tr><th>Алгоритм</th><th>Среднее значение</th><th>Худший случай</th></tr></thead><tbody><tr><td>Space</td><td>O(n)</td><td>O(n)</td></tr><tr><td>Search</td><td>O(n)</td><td>O(n)</td></tr><tr><td>Insert</td><td>O(1)</td><td>O(1)</td></tr><tr><td>Delete</td><td>O(1)</td><td>O(1)</td></tr></tbody></table>',13)])])}const _=e(d,[["render",s]]);export{k as __pageData,_ as default};
